/**
 * MesoLayer (deck.gl) - DNA-like task block visualization
 *
 * Renders task blocks using SolidPolygonLayer for optimal performance.
 * Visible at zoom levels 0.5x - 2.0x (MESO LOD level).
 *
 * Features:
 * - SolidPolygonLayer for all task blocks
 * - Color coding: blue (maintenance), orange (overhaul), gray (inspection)
 * - Conflict indicators: red color on hasConflict tasks
 * - Alternating row backgrounds for readability
 * - Hover/selection/focus highlighting
 *
 * DECK-MIGRATE-002: Replaces R3F InstancedMesh-based MesoLayer
 */

import { SolidPolygonLayer } from '@deck.gl/layers';
import type { TaskRender } from '../../data/types';
import { DEFAULT_VIEW_CONFIG } from '../../data/types';

// ─────────────────────────────────────────────────────────────
// CONSTANTS
// ─────────────────────────────────────────────────────────────

const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;

// Task block height (with padding)
const TASK_HEIGHT = pxPerTrain - 4; // 20px height with 2px padding top/bottom
const TASK_PADDING_Y = 2;

// Color palette matching POC reference (as RGBA)
const COLORS: Record<string, [number, number, number, number]> = {
  blue: [59, 130, 246, 255],     // #3b82f6 - maintenance
  orange: [245, 158, 11, 255],   // #f59e0b - overhaul
  gray: [156, 163, 175, 255],    // #9ca3af - inspection
};

const CONFLICT_COLOR: [number, number, number, number] = [239, 68, 68, 255]; // #ef4444
const SELECTION_COLOR: [number, number, number, number] = [6, 182, 212, 255]; // #06b6d4 cyan-500
const FOCUS_COLOR: [number, number, number, number] = [139, 92, 246, 255]; // #8b5cf6 violet-500

// Row background colors (alternating)
const ROW_BG_EVEN: [number, number, number, number] = [255, 255, 255, 128]; // white 50%
const ROW_BG_ODD: [number, number, number, number] = [248, 250, 252, 128]; // slate-50 50%

// ─────────────────────────────────────────────────────────────
// TYPES
// ─────────────────────────────────────────────────────────────

interface TaskPolygon {
  id: string;
  polygon: [number, number][];
  task: TaskRender;
}

interface RowBackground {
  trainIndex: number;
  polygon: [number, number][];
  isEven: boolean;
}

interface EffectPolygon {
  taskId: string;
  polygon: [number, number][];
}

// ─────────────────────────────────────────────────────────────
// HELPER FUNCTIONS
// ─────────────────────────────────────────────────────────────

/**
 * Brighten a color for hover effect
 */
function brightenColor(
  color: [number, number, number, number],
  factor: number
): [number, number, number, number] {
  return [
    Math.min(255, Math.round(color[0] * factor)),
    Math.min(255, Math.round(color[1] * factor)),
    Math.min(255, Math.round(color[2] * factor)),
    color[3],
  ];
}

/**
 * Apply opacity to a color
 */
function applyOpacity(
  color: [number, number, number, number],
  opacity: number
): [number, number, number, number] {
  return [color[0], color[1], color[2], Math.round(color[3] * opacity)];
}

/**
 * Create a closed rectangle polygon from bounds
 */
function createRectPolygon(
  x1: number,
  y1: number,
  x2: number,
  y2: number
): [number, number][] {
  return [
    [x1, y1],
    [x2, y1],
    [x2, y2],
    [x1, y2],
    [x1, y1], // Close the polygon
  ];
}

// ─────────────────────────────────────────────────────────────
// DATA GENERATION
// ─────────────────────────────────────────────────────────────

/**
 * Generate row background polygons
 */
function generateRowBackgrounds(
  trainCount: number,
  totalDays: number
): RowBackground[] {
  const totalWidth = totalDays * pxPerDay;
  const backgrounds: RowBackground[] = [];

  for (let i = 0; i < trainCount; i++) {
    const y1 = -i * pxPerTrain;
    const y2 = -(i + 1) * pxPerTrain;

    backgrounds.push({
      trainIndex: i,
      polygon: createRectPolygon(0, y1, totalWidth, y2),
      isEven: i % 2 === 0,
    });
  }

  return backgrounds;
}

/**
 * Generate task block polygons
 */
function generateTaskPolygons(tasks: TaskRender[]): TaskPolygon[] {
  return tasks.map((task) => {
    const width = task.duration * pxPerDay;
    const x1 = task.startDay * pxPerDay;
    const x2 = x1 + width;
    const y1 = -task.trainIndex * pxPerTrain - TASK_PADDING_Y;
    const y2 = y1 - TASK_HEIGHT;

    return {
      id: task.id,
      polygon: createRectPolygon(x1, y1, x2, y2),
      task,
    };
  });
}

/**
 * Generate conflict glow polygons (slightly larger behind conflict tasks)
 */
function generateConflictGlows(tasks: TaskRender[]): EffectPolygon[] {
  const conflictTasks = tasks.filter((t) => t.hasConflict);

  return conflictTasks.map((task) => {
    const padding = 3;
    const width = task.duration * pxPerDay + padding * 2;
    const x1 = task.startDay * pxPerDay - padding;
    const x2 = x1 + width;
    const y1 = -task.trainIndex * pxPerTrain - TASK_PADDING_Y + padding;
    const y2 = y1 - TASK_HEIGHT - padding * 2;

    return {
      taskId: task.id,
      polygon: createRectPolygon(x1, y1, x2, y2),
    };
  });
}

/**
 * Generate focus ring polygon (larger ring around focused task)
 */
function generateFocusRing(
  tasks: TaskRender[],
  focusedTaskId: string | null
): EffectPolygon | null {
  if (!focusedTaskId) return null;

  const task = tasks.find((t) => t.id === focusedTaskId);
  if (!task) return null;

  const padding = 4;
  const width = task.duration * pxPerDay + padding * 2;
  const x1 = task.startDay * pxPerDay - padding;
  const x2 = x1 + width;
  const y1 = -task.trainIndex * pxPerTrain - TASK_PADDING_Y + padding;
  const y2 = y1 - TASK_HEIGHT - padding * 2;

  return {
    taskId: task.id,
    polygon: createRectPolygon(x1, y1, x2, y2),
  };
}

// ─────────────────────────────────────────────────────────────
// LAYER FACTORY
// ─────────────────────────────────────────────────────────────

export interface MesoLayerOptions {
  tasks: TaskRender[];
  trainCount: number;
  totalDays?: number;
  visible?: boolean;
  opacity?: number;
  hoveredTaskId?: string | null;
  selectedTaskId?: string | null;
  focusedTaskId?: string | null;
}

/**
 * Create MesoLayer (deck.gl SolidPolygonLayers) for task block visualization
 *
 * Returns an array of layers:
 * - Row backgrounds layer
 * - Conflict glows layer
 * - Focus ring layer
 * - Task blocks layer (on top)
 */
export function createMesoLayers({
  tasks,
  trainCount,
  totalDays = 365 * 10,
  visible = true,
  opacity = 1,
  hoveredTaskId = null,
  selectedTaskId = null,
  focusedTaskId = null,
}: MesoLayerOptions): SolidPolygonLayer[] {
  if (!visible) {
    return [];
  }

  // Generate data
  const rowBackgrounds = generateRowBackgrounds(trainCount, totalDays);
  const taskPolygons = generateTaskPolygons(tasks);
  const conflictGlows = generateConflictGlows(tasks);
  const focusRing = generateFocusRing(tasks, focusedTaskId);

  // Using SolidPolygonLayer[] without generics to avoid type variance issues
  // when pushing layers with different data types
  const layers: SolidPolygonLayer[] = [];

  // Layer 1: Row backgrounds (bottom)
  layers.push(
    new SolidPolygonLayer<RowBackground>({
      id: 'meso-row-backgrounds',
      data: rowBackgrounds,
      getPolygon: (d) => d.polygon,
      getFillColor: (d) =>
        applyOpacity(d.isEven ? ROW_BG_EVEN : ROW_BG_ODD, opacity),
      pickable: false,
      extruded: false,
      updateTriggers: {
        getFillColor: [opacity],
      },
    })
  );

  // Layer 2: Conflict glows (behind task blocks)
  if (conflictGlows.length > 0) {
    layers.push(
      new SolidPolygonLayer<EffectPolygon>({
        id: 'meso-conflict-glows',
        data: conflictGlows,
        getPolygon: (d) => d.polygon,
        getFillColor: applyOpacity([239, 68, 68, 76], opacity), // red at 30%
        pickable: false,
        extruded: false,
        updateTriggers: {
          getFillColor: [opacity],
        },
      })
    );
  }

  // Layer 3: Focus ring (behind focused task)
  if (focusRing) {
    layers.push(
      new SolidPolygonLayer<EffectPolygon>({
        id: 'meso-focus-ring',
        data: [focusRing],
        getPolygon: (d) => d.polygon,
        getFillColor: applyOpacity([139, 92, 246, 102], opacity), // violet at 40%
        pickable: false,
        extruded: false,
        updateTriggers: {
          getFillColor: [opacity],
        },
      })
    );
  }

  // Layer 4: Task blocks (top)
  layers.push(
    new SolidPolygonLayer<TaskPolygon>({
      id: 'meso-task-blocks',
      data: taskPolygons,
      getPolygon: (d) => d.polygon,
      getFillColor: (d) => {
        const { task } = d;
        const isSelected = task.id === selectedTaskId;
        const isFocused = task.id === focusedTaskId;
        const isHovered = task.id === hoveredTaskId;

        let color: [number, number, number, number];

        if (isSelected) {
          color = SELECTION_COLOR;
        } else if (isFocused) {
          color = FOCUS_COLOR;
        } else if (task.hasConflict) {
          color = isHovered ? brightenColor(CONFLICT_COLOR, 1.5) : CONFLICT_COLOR;
        } else {
          const baseColor = COLORS[task.color] || COLORS.gray;
          color = isHovered ? brightenColor(baseColor, 1.5) : baseColor;
        }

        return applyOpacity(color, opacity);
      },
      pickable: true,
      extruded: false,
      updateTriggers: {
        getFillColor: [opacity, hoveredTaskId, selectedTaskId, focusedTaskId],
      },
    })
  );

  return layers;
}

/**
 * Export constants for use in other modules
 */
export const MESO_CONSTANTS = {
  TASK_HEIGHT,
  TASK_PADDING_Y,
  COLORS,
  CONFLICT_COLOR,
  SELECTION_COLOR,
  FOCUS_COLOR,
};

