     1→/**
     2→ * D3-Brush TimeScrubber POC
     3→ *
     4→ * Direct D3 brush integration with React using useRef and useEffect.
     5→ * Maximum flexibility for custom brush behavior.
     6→ *
     7→ * Pros:
     8→ * - Maximum flexibility and control
     9→ * - Can be combined with any visualization library
    10→ * - Industry standard - well documented
    11→ *
    12→ * Cons:
    13→ * - Requires careful React lifecycle management
    14→ * - Imperative API doesn't fit React paradigm
    15→ * - Need to handle bidirectional sync manually
    16→ */
    17→
    18→import React, { useRef, useEffect, useMemo, useCallback } from 'react';
    19→import * as d3 from 'd3';
    20→import { brushX } from 'd3-brush';
    21→import type { BrushSelection } from 'd3-brush';
    22→import { scaleTime, scaleLinear } from 'd3-scale';
    23→import { area, curveMonotoneX } from 'd3-shape';
    24→import { axisBottom } from 'd3-axis';
    25→import type { TimeSeriesPoint } from './mockData';
    26→
    27→interface D3BrushTimeScrubberProps {
    28→  /** Time series data for density visualization */
    29→  data: TimeSeriesPoint[];
    30→  /** Width of the component */
    31→  width: number;
    32→  /** Height of the component */
    33→  height: number;
    34→  /** Callback when brush selection changes */
    35→  onBrushChange?: (domain: [Date, Date] | null) => void;
    36→  /** External selection (for bidirectional sync) */
    37→  selection?: [Date, Date] | null;
    38→  /** Margin around the chart */
    39→  margin?: { top: number; right: number; bottom: number; left: number };
    40→  /** Fill color for area */
    41→  fillColor?: string;
    42→  /** Stroke color for line */
    43→  strokeColor?: string;
    44→  /** Brush selection color */
    45→  brushColor?: string;
    46→}
    47→
    48→const defaultMargin = { top: 10, right: 10, bottom: 25, left: 10 };
    49→
    50→export const D3BrushTimeScrubber: React.FC<D3BrushTimeScrubberProps> = ({
    51→  data,
    52→  width,
    53→  height,
    54→  onBrushChange,
    55→  selection,
    56→  margin = defaultMargin,
    57→  fillColor = 'rgba(99, 102, 241, 0.3)',
    58→  strokeColor = '#4f46e5',
    59→  brushColor = 'rgba(99, 102, 241, 0.2)',
    60→}) => {
    61→  const svgRef = useRef<SVGSVGElement>(null);
    62→  const brushGroupRef = useRef<SVGGElement>(null);
    63→  const brushBehaviorRef = useRef<ReturnType<typeof brushX> | null>(null);
    64→  const isInternalUpdateRef = useRef(false);
    65→
    66→  // Calculate inner dimensions
    67→  const innerWidth = width - margin.left - margin.right;
    68→  const innerHeight = height - margin.top - margin.bottom;
    69→
    70→  // Create scales
    71→  const xScale = useMemo(() => {
    72→    const extent = d3.extent(data, (d) => d.date) as [Date, Date];
    73→    return scaleTime().domain(extent).range([0, innerWidth]);
    74→  }, [data, innerWidth]);
    75→
    76→  const yScale = useMemo(() => {
    77→    const maxValue = d3.max(data, (d) => d.value) || 0;
    78→    return scaleLinear()
    79→      .domain([0, maxValue * 1.1])
    80→      .range([innerHeight, 0]);
    81→  }, [data, innerHeight]);
    82→
    83→  // Handle brush events
    84→  const handleBrush = useCallback(
    85→    (event: d3.D3BrushEvent<unknown>) => {
    86→      // Check if this is from user interaction (has sourceEvent)
    87→      // to prevent infinite loops with programmatic updates
    88→      if (!event.sourceEvent) return;
    89→
    90→      const sel = event.selection as [number, number] | null;
    91→      if (sel && onBrushChange) {
    92→        const [x0, x1] = sel;
    93→        onBrushChange([xScale.invert(x0), xScale.invert(x1)]);
    94→      } else if (!sel && onBrushChange) {
    95→        onBrushChange(null);
    96→      }
    97→    },
    98→    [xScale, onBrushChange]
    99→  );
   100→
   101→  // Initialize D3 brush
   102→  useEffect(() => {
   103→    if (!brushGroupRef.current) return;
   104→
   105→    const brushG = d3.select(brushGroupRef.current);
   106→
   107→    // Create brush behavior
   108→    brushBehaviorRef.current = brushX()
   109→      .extent([
   110→        [0, 0],
   111→        [innerWidth, innerHeight],
   112→      ])
   113→      .on('brush end', handleBrush);
   114→
   115→    // Apply brush to group
   116→    brushG.call(brushBehaviorRef.current);
   117→
   118→    // Style the brush
   119→    brushG.select('.selection').attr('fill', brushColor).attr('stroke', strokeColor);
   120→
   121→    // Style the handles
   122→    brushG
   123→      .selectAll('.handle')
   124→      .attr('fill', strokeColor)
   125→      .attr('rx', 3)
   126→      .attr('ry', 3);
   127→
   128→    return () => {
   129→      brushG.on('.brush', null);
   130→    };
   131→  }, [innerWidth, innerHeight, handleBrush, brushColor, strokeColor]);
   132→
   133→  // Sync external selection to brush (programmatic updates)
   134→  useEffect(() => {
   135→    if (!brushGroupRef.current || !brushBehaviorRef.current) return;
   136→    if (isInternalUpdateRef.current) {
   137→      isInternalUpdateRef.current = false;
   138→      return;
   139→    }
   140→
   141→    const brushG = d3.select(brushGroupRef.current);
   142→
   143→    if (selection) {
   144→      const [d0, d1] = selection;
   145→      const pixelSelection: [number, number] = [xScale(d0), xScale(d1)];
   146→
   147→      // Use transition for smooth update
   148→      brushG.transition().duration(200).call(brushBehaviorRef.current.move, pixelSelection);
   149→    } else {
   150→      brushG.call(brushBehaviorRef.current.move, null);
   151→    }
   152→  }, [selection, xScale]);
   153→
   154→  // Create area generator
   155→  const areaGenerator = useMemo(() => {
   156→    return area<TimeSeriesPoint>()
   157→      .x((d) => xScale(d.date))
   158→      .y0(innerHeight)
   159→      .y1((d) => yScale(d.value))
   160→      .curve(curveMonotoneX);
   161→  }, [xScale, yScale, innerHeight]);
   162→
   163→  // Create line generator
   164→  const lineGenerator = useMemo(() => {
   165→    return d3
   166→      .line<TimeSeriesPoint>()
   167→      .x((d) => xScale(d.date))
   168→      .y((d) => yScale(d.value))
   169→      .curve(curveMonotoneX);
   170→  }, [xScale, yScale]);
   171→
   172→  // Generate paths
   173→  const areaPath = useMemo(() => areaGenerator(data) || '', [areaGenerator, data]);
   174→  const linePath = useMemo(() => lineGenerator(data) || '', [lineGenerator, data]);
   175→
   176→  // Render X axis
   177→  useEffect(() => {
   178→    if (!svgRef.current) return;
   179→
   180→    const svg = d3.select(svgRef.current);
   181→    const axisG = svg.select('.x-axis');
   182→
   183→    const axis = axisBottom(xScale)
   184→      .ticks(width > 400 ? 6 : 3)
   185→      .tickFormat((d) => {
   186→        const date = d as Date;
   187→        return date.toLocaleDateString('en-US', { month: 'short', year: '2-digit' });
   188→      });
   189→
   190→    axisG.call(axis as any);
   191→  }, [xScale, width]);
   192→
   193→  if (width < 100 || height < 50) {
   194→    return <div>Container too small</div>;
   195→  }
   196→
   197→  return (
   198→    <svg ref={svgRef} width={width} height={height}>
   199→      <defs>
   200→        <linearGradient id="d3-area-gradient" x1="0" y1="0" x2="0" y2="1">
   201→          <stop offset="0%" stopColor={strokeColor} stopOpacity={0.4} />
   202→          <stop offset="100%" stopColor={strokeColor} stopOpacity={0.05} />
   203→        </linearGradient>
   204→      </defs>
   205→
   206→      <g transform={`translate(${margin.left},${margin.top})`}>
   207→        {/* Area */}
   208→        <path d={areaPath} fill="url(#d3-area-gradient)" />
   209→
   210→        {/* Line */}
   211→        <path d={linePath} fill="none" stroke={strokeColor} strokeWidth={1.5} />
   212→
   213→        {/* Brush group */}
   214→        <g ref={brushGroupRef} className="brush" />
   215→
   216→        {/* X Axis */}
   217→        <g
   218→          className="x-axis"
   219→          transform={`translate(0,${innerHeight})`}
   220→          style={{ fontSize: 10, color: '#666' }}
   221→        />
   222→      </g>
   223→    </svg>
   224→  );
   225→};
   226→
   227→export default D3BrushTimeScrubber;
   228→

