/**
 * D3-Brush TimeScrubber POC
 *
 * Direct D3 brush integration with React using useRef and useEffect.
 * Maximum flexibility for custom brush behavior.
 *
 * Pros:
 * - Maximum flexibility and control
 * - Can be combined with any visualization library
 * - Industry standard - well documented
 *
 * Cons:
 * - Requires careful React lifecycle management
 * - Imperative API doesn't fit React paradigm
 * - Need to handle bidirectional sync manually
 */

import React, { useRef, useEffect, useMemo, useCallback } from 'react';
import * as d3 from 'd3';
import { brushX } from 'd3-brush';
import type { BrushSelection } from 'd3-brush';
import { scaleTime, scaleLinear } from 'd3-scale';
import { area, curveMonotoneX } from 'd3-shape';
import { axisBottom } from 'd3-axis';
import type { TimeSeriesPoint } from './mockData';

interface D3BrushTimeScrubberProps {
  /** Time series data for density visualization */
  data: TimeSeriesPoint[];
  /** Width of the component */
  width: number;
  /** Height of the component */
  height: number;
  /** Callback when brush selection changes */
  onBrushChange?: (domain: [Date, Date] | null) => void;
  /** External selection (for bidirectional sync) */
  selection?: [Date, Date] | null;
  /** Margin around the chart */
  margin?: { top: number; right: number; bottom: number; left: number };
  /** Fill color for area */
  fillColor?: string;
  /** Stroke color for line */
  strokeColor?: string;
  /** Brush selection color */
  brushColor?: string;
}

const defaultMargin = { top: 10, right: 10, bottom: 25, left: 10 };

export const D3BrushTimeScrubber: React.FC<D3BrushTimeScrubberProps> = ({
  data,
  width,
  height,
  onBrushChange,
  selection,
  margin = defaultMargin,
  fillColor = 'rgba(99, 102, 241, 0.3)',
  strokeColor = '#4f46e5',
  brushColor = 'rgba(99, 102, 241, 0.2)',
}) => {
  const svgRef = useRef<SVGSVGElement>(null);
  const brushGroupRef = useRef<SVGGElement>(null);
  const brushBehaviorRef = useRef<ReturnType<typeof brushX> | null>(null);
  const isInternalUpdateRef = useRef(false);

  // Calculate inner dimensions
  const innerWidth = width - margin.left - margin.right;
  const innerHeight = height - margin.top - margin.bottom;

  // Create scales
  const xScale = useMemo(() => {
    const extent = d3.extent(data, (d) => d.date) as [Date, Date];
    return scaleTime().domain(extent).range([0, innerWidth]);
  }, [data, innerWidth]);

  const yScale = useMemo(() => {
    const maxValue = d3.max(data, (d) => d.value) || 0;
    return scaleLinear()
      .domain([0, maxValue * 1.1])
      .range([innerHeight, 0]);
  }, [data, innerHeight]);

  // Handle brush events
  const handleBrush = useCallback(
    (event: d3.D3BrushEvent<unknown>) => {
      // Check if this is from user interaction (has sourceEvent)
      // to prevent infinite loops with programmatic updates
      if (!event.sourceEvent) return;

      const sel = event.selection as [number, number] | null;
      if (sel && onBrushChange) {
        const [x0, x1] = sel;
        onBrushChange([xScale.invert(x0), xScale.invert(x1)]);
      } else if (!sel && onBrushChange) {
        onBrushChange(null);
      }
    },
    [xScale, onBrushChange]
  );

  // Initialize D3 brush
  useEffect(() => {
    if (!brushGroupRef.current) return;

    const brushG = d3.select(brushGroupRef.current);

    // Create brush behavior
    brushBehaviorRef.current = brushX()
      .extent([
        [0, 0],
        [innerWidth, innerHeight],
      ])
      .on('brush end', handleBrush);

    // Apply brush to group
    brushG.call(brushBehaviorRef.current);

    // Style the brush
    brushG.select('.selection').attr('fill', brushColor).attr('stroke', strokeColor);

    // Style the handles
    brushG
      .selectAll('.handle')
      .attr('fill', strokeColor)
      .attr('rx', 3)
      .attr('ry', 3);

    return () => {
      brushG.on('.brush', null);
    };
  }, [innerWidth, innerHeight, handleBrush, brushColor, strokeColor]);

  // Sync external selection to brush (programmatic updates)
  useEffect(() => {
    if (!brushGroupRef.current || !brushBehaviorRef.current) return;
    if (isInternalUpdateRef.current) {
      isInternalUpdateRef.current = false;
      return;
    }

    const brushG = d3.select(brushGroupRef.current);

    if (selection) {
      const [d0, d1] = selection;
      const pixelSelection: [number, number] = [xScale(d0), xScale(d1)];

      // Use transition for smooth update
      brushG.transition().duration(200).call(brushBehaviorRef.current.move, pixelSelection);
    } else {
      brushG.call(brushBehaviorRef.current.move, null);
    }
  }, [selection, xScale]);

  // Create area generator
  const areaGenerator = useMemo(() => {
    return area<TimeSeriesPoint>()
      .x((d) => xScale(d.date))
      .y0(innerHeight)
      .y1((d) => yScale(d.value))
      .curve(curveMonotoneX);
  }, [xScale, yScale, innerHeight]);

  // Create line generator
  const lineGenerator = useMemo(() => {
    return d3
      .line<TimeSeriesPoint>()
      .x((d) => xScale(d.date))
      .y((d) => yScale(d.value))
      .curve(curveMonotoneX);
  }, [xScale, yScale]);

  // Generate paths
  const areaPath = useMemo(() => areaGenerator(data) || '', [areaGenerator, data]);
  const linePath = useMemo(() => lineGenerator(data) || '', [lineGenerator, data]);

  // Render X axis
  useEffect(() => {
    if (!svgRef.current) return;

    const svg = d3.select(svgRef.current);
    const axisG = svg.select('.x-axis');

    const axis = axisBottom(xScale)
      .ticks(width > 400 ? 6 : 3)
      .tickFormat((d) => {
        const date = d as Date;
        return date.toLocaleDateString('en-US', { month: 'short', year: '2-digit' });
      });

    axisG.call(axis as any);
  }, [xScale, width]);

  if (width < 100 || height < 50) {
    return <div>Container too small</div>;
  }

  return (
    <svg ref={svgRef} width={width} height={height}>
      <defs>
        <linearGradient id="d3-area-gradient" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor={strokeColor} stopOpacity={0.4} />
          <stop offset="100%" stopColor={strokeColor} stopOpacity={0.05} />
        </linearGradient>
      </defs>

      <g transform={`translate(${margin.left},${margin.top})`}>
        {/* Area */}
        <path d={areaPath} fill="url(#d3-area-gradient)" />

        {/* Line */}
        <path d={linePath} fill="none" stroke={strokeColor} strokeWidth={1.5} />

        {/* Brush group */}
        <g ref={brushGroupRef} className="brush" />

        {/* X Axis */}
        <g
          className="x-axis"
          transform={`translate(0,${innerHeight})`}
          style={{ fontSize: 10, color: '#666' }}
        />
      </g>
    </svg>
  );
};

export default D3BrushTimeScrubber;

