   587→
   588→// =============================================================================
   589→// EXECUTION OVERLAY (HTML-based for detailed view)
   590→// =============================================================================
   591→
   592→interface ExecutionOverlayProps {
   593→  tasks: Task[];
   594→  trains: Train[];
   595→  cameraX: number;
   596→  cameraY: number;
   597→  zoom: number;
   598→  width: number;
