   601→}
   602→
   603→const ExecutionOverlay: React.FC<ExecutionOverlayProps> = ({
   604→  tasks,
   605→  trains,
   606→  cameraX,
   607→  cameraY,
   608→  zoom,
   609→  width,
   610→  height,
   611→  opacity,
   612→}) => {
   613→  const ROW_HEIGHT = 80;
   614→  const EXEC_PX_PER_DAY = 80;
   615→  const HEADER_HEIGHT = 50;
   616→
   617→  // Filter tasks for visible range
   618→  const visibleTasks = useMemo(() => {
   619→    const startTrain = Math.max(0, Math.floor(cameraY));
   620→    const endTrain = Math.min(trains.length - 1, Math.ceil(cameraY + height / ROW_HEIGHT));
